    ('PLS', '98', 2013, 'Altera o art. 93 e acrescenta os arts. 99-A, 124-A e 124-B à Lei nº 8.666, de 21 de junho de 1993, que regulamenta o art. 37, inciso XXI da Constituição Federal, institui normas para licitações e contratos da Administração Pública e dá outras providências, para estabelecer pena para o servidor que divulgar a identificação das pessoas que tenham retirado o ato de convocação ou sido convidados para certame licitatório, definir o alcance das penas previstas na Lei e para estabelecer diretrizes básicas de transparência nos processos licitatórios.', 'Senado', '111867', 'https://www25.senado.leg.br/web/atividade/materias/-/materia/111867', 'joao-capiberibe-senado-completo-autoria-substantiva-2003-2018-20260505', 'inventario_completo_senado_autoria_substantiva_2003_2018_20260505', '{"proposicao_id_api":"111867","descricao_identificacao":"PLS 98/2013","data_apresentacao":"2013-03-26","casa":"SF","codigo_parlamentar_senado":3394,"indicador_autor_principal_endpoint_senador":"Sim","indicador_outros_autores_endpoint_senador":"Não","num_ordem_autor":1,"total_autores":1,"partido_autor_no_protocolo":"PSB","uf_autor_no_protocolo":"AP","autor_nome":"João Capiberibe","fonte":"Senado Federal Dados Abertos","autorias_endpoint":"https://legis.senado.leg.br/dadosabertos/senador/3394/autorias.json","autoria_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/autoria/111867.json","detalhe_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/111867.json","public_url":"https://www25.senado.leg.br/web/atividade/materias/-/materia/111867","coverage_id":"joao-capiberibe-senado-completo-autoria-substantiva-2003-2018-20260505","coverage_scope":"inventario_completo_senado_autoria_substantiva_2003_2018_20260505","lote":"A","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"joao-capiberibe-senado-lote-a-20260505","snapshot_consulta_em":"2026-05-06T01:24:30.640Z"}'::jsonb),
