    ('PLS', '261', 2013, 'Altera os arts. 22 e 93, e acrescenta os arts. 33-A, 99-A e 124-A à Lei nº 8.666, de 21 de junho de 1993, que regulamenta o art. 37, inciso XXI, da Constituição Federal, institui normas para licitações e contratos da Administração Pública e dá outras providências, para redefinir a modalidade de licitação convite, estabelecer pena para o servidor que divulgar a identificação das pessoas que tenham retirado o ato de convocação ou sido convidados para certame licitatório, definir o alcance das penas previstas na Lei e estabelecer diretrizes básicas de transparência nos processos licitatórios, entre outras providências.', 'Senado', '113453', 'https://www25.senado.leg.br/web/atividade/materias/-/materia/113453', 'joao-capiberibe-senado-completo-autoria-substantiva-2003-2018-20260505', 'inventario_completo_senado_autoria_substantiva_2003_2018_20260505', '{"proposicao_id_api":"113453","descricao_identificacao":"PLS 261/2013","data_apresentacao":"2013-07-02","casa":"SF","codigo_parlamentar_senado":3394,"indicador_autor_principal_endpoint_senador":"Sim","indicador_outros_autores_endpoint_senador":"Não","num_ordem_autor":1,"total_autores":1,"partido_autor_no_protocolo":"PSB","uf_autor_no_protocolo":"AP","autor_nome":"João Capiberibe","fonte":"Senado Federal Dados Abertos","autorias_endpoint":"https://legis.senado.leg.br/dadosabertos/senador/3394/autorias.json","autoria_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/autoria/113453.json","detalhe_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/113453.json","public_url":"https://www25.senado.leg.br/web/atividade/materias/-/materia/113453","coverage_id":"joao-capiberibe-senado-completo-autoria-substantiva-2003-2018-20260505","coverage_scope":"inventario_completo_senado_autoria_substantiva_2003_2018_20260505","lote":"A","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"joao-capiberibe-senado-lote-a-20260505","snapshot_consulta_em":"2026-0