    ('PEC', '30', 2014, 'Acrescenta o art. 27-A, altera o § 3º do art. 32 e acrescenta § 2º ao art. 75, todos da Constituição Federal, bem como insere artigo no Ato das Disposições Constitucionais Transitórias; com o objetivo de fixar limite máximo para as despesas das Assembleias Legislativas dos Estados, da Câmara Legislativa do Distrito Federal e dos Tribunais de Contas dos Estados e do Distrito Federal.', 'Senado', '118418', 'https://www25.senado.leg.br/web/atividade/materias/-/materia/118418', 'joao-capiberibe-senado-completo-autoria-substantiva-2003-2018-20260505', 'inventario_completo_senado_autoria_substantiva_2003_2018_20260505', '{"proposicao_id_api":"118418","descricao_identificacao":"PEC 30/2014","data_apresentacao":"2014-08-06","casa":"SF","codigo_parlamentar_senado":3394,"indicador_autor_principal_endpoint_senador":"Sim","indicador_outros_autores_endpoint_senador":"Sim","num_ordem_autor":1,"total_autores":31,"partido_autor_no_protocolo":"PSB","uf_autor_no_protocolo":"AP","autor_nome":"João Capiberibe","fonte":"Senado Federal Dados Abertos","autorias_endpoint":"https://legis.senado.leg.br/dadosabertos/senador/3394/autorias.json","autoria_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/autoria/118418.json","detalhe_endpoint":"https://legis.senado.leg.br/dadosabertos/materia/118418.json","public_url":"https://www25.senado.leg.br/web/atividade/materias/-/materia/118418","coverage_id":"joao-capiberibe-senado-completo-autoria-substantiva-2003-2018-20260505","coverage_scope":"inventario_completo_senado_autoria_substantiva_2003_2018_20260505","lote":"A","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"joao-capiberibe-senado-lote-a-20260505","snapshot_consulta_em":"2026-05-06T01:24:30.640Z"}'::jsonb),
